/* AUTOGENERATED-ISH — keep small, no transpilation. Vanilla JS + Alpine. */

// Fallback used when the user submits without picking a country from
// the typeahead. Same as Google's "no params" default.
const DEFAULT_REGION = Object.freeze({
    name:  'United States',
    gl:    'US',
    lang:  'English',
    hl:    'en',
    dir:   'ltr',
    url:   'https://www.google.com/search',
    label: 'United States — English (us/en)',
});

/**  Component factory.  Belt-and-suspenders approach:
 *   1. exposed as `window.serpChecker` so the view can call it directly
 *   2. also registered via Alpine.data() on `alpine:init` so any
 *      load-order quirk still finds it.
 *
 *  Globals (window.SEO_LOCAL_RANK_REGIONS / _CONFIG) are read at
 *  instantiation time, so they need to be defined before this runs.
 *  The recommended script order in layout.php is
 *      defer  regions.generated.js
 *      defer  app.js  (this file)
 *      defer  alpinejs
 *  so the defer queue executes regions → app → alpine and every
 *  global is in place when Alpine.start() walks the DOM. */


/**
 * Alpine.js component driving the SERP checker form.
 *
 * - country/language typeahead powered by regions.generated.js
 * - address autocomplete & geocoding powered by **Photon** — a keyless,
 *   OSM-based geocoder hosted at https://photon.komoot.io. License: ODbL
 *   (OpenStreetMap data) — attribution shown in the view.
 * - UULE encoding mirrors valentin.app's `updateLatLng` → `genGeoCode`
 *   pipeline (floor to 1e7, then round back to 1e7).
 * - localized Google search URL opened in a new tab on submit
 *
 * No Google Maps JS API is loaded; no GOOGLE_MAPS_API_KEY is required.
 */
window.serpChecker = function serpChecker({ regions, config }) {
    return {
        /* ---------------------------- state ---------------------------- */
        regions,
        config,
        state: {
            q:           '',
            // Default to en/US so the submit button enables the moment a
            // keyword is typed. Picks from the typeahead overwrite these.
            hl:          DEFAULT_REGION.hl,
            gl:          DEFAULT_REGION.gl,
            endpoint:    (config.defaultEndpoint || DEFAULT_REGION.url),
            placeText:   '',
            lat:         null,
            lng:         null,
            uule:        '',
        },

        regionQuery: '',
        regionOpen: false,

        geocoding: false, // Geocode button "in flight" indicator

        /* ------------------- Photon autocomplete state ----------------- */
        placeSuggestions: [],
        placeOpen:        false,
        placeError:       '',
        _placeReqId:      0,     // monotonic — newer responses overwrite older
        _placeAbort:      null,  // AbortController for the in-flight fetch
        _placeDebounce:   null,  // setTimeout handle for the 220ms debounce

        /* -------------------------- lifecycle ------------------------- */
        init() {
            try { if (window.console?.log) console.log('[seolocalrank] init, build=', window.SEO_LOCAL_RANK_BUILD, 'regions=', this.regions?.length); } catch (_) {}

            try {
                const cached = JSON.parse(localStorage.getItem('seolocalrank:lastRegion') || 'null');
                if (cached && this.regions.some(r =>
                    r.gl === cached.gl && r.hl === cached.hl && r.name === cached.name
                )) {
                    this.applyRegion(cached);
                    this.regionQuery = cached.label;
                }
            } catch (_) { /* ignore */ }
        },

        /* ---------------------- region typeahead ---------------------- */
        filteredRegions() {
            const q = (this.regionQuery || '').trim().toLowerCase();
            if (!q) return this.regions.slice(0, 12);
            return this.regions.filter(r =>
                r.name.toLowerCase().includes(q)  ||
                r.lang.toLowerCase().includes(q)  ||
                r.hl.toLowerCase().includes(q)    ||
                r.gl.toLowerCase().includes(q)
            );
        },

        tryAutoSelectRegion() {
            const q = (this.regionQuery || '').trim().toLowerCase();
            if (!q) return;
            const matches = this.filteredRegions();
            if (!matches.length) return;
            const exact = matches.find(r =>
                r.name.toLowerCase() === q ||
                r.label.toLowerCase() === q ||
                `${r.name} \u2014 ${r.lang}`.toLowerCase() === q,
            );
            if (exact) this.selectRegion(exact);
        },

        selectRegion(r) {
            this.applyRegion(r);
            this.regionQuery = r.label;
            this.regionOpen = false;
            try {
                localStorage.setItem('seolocalrank:lastRegion', JSON.stringify(r));
            } catch (_) { /* ignore */ }
        },

        applyRegion(r) {
            this.state.hl       = r.hl;
            this.state.gl       = r.gl;
            this.state.endpoint = r.url;
        },

        /* ------------------ Photon typeahead (free, keyless) ------------------- */
        /*
         * Photon (https://photon.komoot.io) is an open-source OSM-based
         * geocoder with no API key. License: ODbL — attribution rendered
         * in the view as "Powered by Photon / OpenStreetMap".
         *
         * This replaces the deprecated Google Places JS API.
         */
        searchPlaces() {
            const q = (this.state.placeText || '').trim();

            // Below 3 chars Photon's quality collapses and every keystroke
            // would burn a request. Bail out and clear any in-flight fetch.
            if (q.length < 3) {
                this.placeSuggestions = [];
                this.placeOpen = false;
                this.placeError = '';
                this._abortActive();
                clearTimeout(this._placeDebounce);
                return;
            }

            // Race-protect: bump a monotonic id so a slow earlier response
            // can't overwrite the suggestions from a newer keystroke.
            const reqId = ++this._placeReqId;
            this._abortActive();
            const ctrl = new AbortController();
            this._placeAbort = ctrl;

            clearTimeout(this._placeDebounce);
            this._placeDebounce = setTimeout(() => {
                // The user might have cleared / shortened the query
                // while the debounce was queued — re-validate.
                const now = (this.state.placeText || '').trim();
                if (this._placeReqId !== reqId || ctrl.signal.aborted || now !== q) return;

                fetch(`https://photon.komoot.io/api/?q=${encodeURIComponent(q)}&limit=5`, {
                    signal: ctrl.signal,
                    headers: { 'Accept': 'application/json' },
                })
                    .then((r) => {
                        if (!r.ok) throw new Error('HTTP ' + r.status);
                        return r.json();
                    })
                    .then((data) => {
                        if (this._placeReqId !== reqId) return;
                        const features = Array.isArray(data?.features) ? data.features : [];
                        this.placeSuggestions = features.slice(0, 5)
                            .map((f) => this._normalizePhotonFeature(f, q))
                            .filter((s) => s.lat != null && s.lng != null);
                        this.placeOpen = this.placeSuggestions.length > 0;
                        this.placeError = this.placeSuggestions.length
                            ? ''
                            : 'No matches — try a broader query.';
                    })
                    .catch((e) => {
                        if (ctrl.signal.aborted || e?.name === 'AbortError') return;
                        if (this._placeReqId !== reqId) return;
                        this.placeSuggestions = [];
                        this.placeOpen = false;
                        // Only surface the error if the query is still long
                        // enough — otherwise it just means "we cleared".
                        this.placeError = (this.state.placeText || '').trim().length >= 3
                            ? 'Address search unavailable — try again or skip location.'
                            : '';
                    });
            }, 220);
        },

        _abortActive() {
            try { this._placeAbort?.abort(); } catch (_) { /* ignore */ }
            this._placeAbort = null;
        },

        _normalizePhotonFeature(f, fallbackQuery) {
            const p = f.properties || {};
            const coords = f.geometry?.coordinates || [];
            const lng = coords[0];
            const lat = coords[1];
            const label = [
                p.name, p.street, p.housenumber,
                p.city || p.town || p.village || p.county,
                p.state, p.postcode, p.country,
            ].filter(Boolean).join(', ') || p.name || fallbackQuery;

            const kind =
                p.osm_value === 'city' || p.osm_value === 'town' || p.osm_value === 'village' ? 'City' :
                p.osm_value === 'suburb' || p.osm_value === 'neighbourhood' ? 'Area' :
                ['house', 'building', 'address'].includes(p.osm_value) ? 'Address' :
                p.osm_value === 'country' ? 'Country' :
                p.osm_value === 'state' ? 'Region' :
                p.osm_value === 'postcode' ? 'Postal code' :
                p.osm_value ? p.osm_value.charAt(0).toUpperCase() + p.osm_value.slice(1) :
                'Place';

            return {
                label,
                lat: typeof lat === 'number' ? lat : null,
                lng: typeof lng === 'number' ? lng : null,
                kind,
            };
        },

        pickPlace(s) {
            if (!s || s.lat == null || s.lng == null) return;
            this.state.placeText  = s.label;
            this.state.lat        = s.lat;
            this.state.lng        = s.lng;
            this.state.uule       = this.makeUULE(s.lat, s.lng);
            this.placeSuggestions = [];
            this.placeOpen        = false;
            this.placeError       = '';
            this._abortActive();
        },

        /*
         * Manual "Geocode" button: forces a no-debounce fetch and
         * auto-picks the top result. Useful when the user's text has
         * zero matching suggestions but Photon still has a single
         * canonical match.
         */
        forceGeocode() {
            const q = (this.state.placeText || '').trim();
            if (!q || q.length < 3) {
                this.placeError = 'Type at least 3 characters.';
                return;
            }
            // Already resolved against the current text — nothing to do.
            if (this.state.lat != null && this.state.lng != null && this.state.placeText === q) {
                this.placeError = '';
                return;
            }
            this.geocoding = true;
            this._abortActive();
            clearTimeout(this._placeDebounce);
            const reqId = ++this._placeReqId;
            const ctrl = new AbortController();
            this._placeAbort = ctrl;

            fetch(`https://photon.komoot.io/api/?q=${encodeURIComponent(q)}&limit=1`, {
                signal: ctrl.signal,
                headers: { 'Accept': 'application/json' },
            })
                .then((r) => {
                    if (!r.ok) throw new Error('HTTP ' + r.status);
                    return r.json();
                })
                .then((data) => {
                    if (this._placeReqId !== reqId) return;
                    const f = data?.features?.[0];
                    if (!f) {
                        this.placeError = 'No match for that address.';
                        return;
                    }
                    const norm = this._normalizePhotonFeature(f, q);
                    if (norm.lat == null || norm.lng == null) {
                        this.placeError = 'No coordinates in Photon response.';
                        return;
                    }
                    // Reuse pickPlace so all the side-effects stay in one
                    // place (uuLe, suggestions, errors all reset).
                    this.pickPlace(norm);
                })
                .catch((e) => {
                    if (ctrl.signal.aborted || e?.name === 'AbortError') return;
                    if (this._placeReqId !== reqId) return;
                    this.placeError = 'Geocoding failed: ' + (e?.message || e);
                })
                .finally(() => {
                    if (this._placeReqId === reqId) this.geocoding = false;
                });
        },

        /* ------------------------ UULE builder ------------------------ */
        /*
         * Mirrors valentin.app's updateLatLng → genGeoCode:
         *   1. floor coordinates to 7 decimal places
         *   2. round back to 1e7 scaled ints
         * Then assemble the canonical role:1 ... radius payload and base64-
         * url-encode it with `a ` prefix.
         */
        makeUULE(lat, lng) {
            const lat7 = Math.floor(lat * 1e7) / 1e7;
            const lng7 = Math.floor(lng * 1e7) / 1e7;
            const latE = Math.round(1e7 * lat7);
            const lngE = Math.round(1e7 * lng7);
            const ts   = String(1e3 * Date.now());
            const radius = 150 * 620;

            const payload =
                'role:1' +
                '\nproducer:12' +
                '\nprovenance:6' +
                `\ntimestamp:${ts}` +
                `\nlatlng{\nlatitude_e7:${latE}` +
                `\nlongitude_e7:${lngE}` +
                '\n}\nradius:' + radius;

            const b64 = btoa(payload).replace(/\+/g, '-').replace(/\//g, '_');
            return 'a ' + b64;
        },

        /* --------------------------- submit --------------------------- */
        submit() {
            if (!this.state.q) return;

            const hl       = this.state.hl || DEFAULT_REGION.hl;
            const gl       = this.state.gl || DEFAULT_REGION.gl;
            const endpoint = this.state.endpoint || DEFAULT_REGION.url;

            const params = new URLSearchParams({
                q:  this.state.q,
                hl,
                gl,
                ie: 'utf-8',
                oe: 'utf-8',
                pws: '0',
            });
            if (this.state.uule) params.set('uule', this.state.uule);

            window.open(`${endpoint}?${params.toString()}`, '_blank', 'noopener,noreferrer');
        },
    };
};

// Belt-and-suspenders registration. The first arg to Alpine.data is the
// class name; the view then binds via `x-data="serpChecker({...})"`.
// Works even when the page hits a stray load-order race.
document.addEventListener('alpine:init', () => {
    if (!window.Alpine?.data) return;
    window.Alpine.data('serpChecker', (cfg) => window.serpChecker(cfg));
});
